```
from pyspider.libs.base_handler import *


class Handler(BaseHandler):
    crawl_config = {
    }

    @every(minutes=24 * 60)
    def on_start(self):
        self.crawl('http://www.nowdl.cn/all.html', callback=self.index_page)

    @config(age=10 * 24 * 60 * 60)
